UPDATE sched_task
SET dispatch_failures = (#{currentDispatchFailures,jdbcType=TINYINT} + 1)
WHERE task_id = #{taskId,jdbcType=BIGINT}
  AND dispatch_failures = #{currentDispatchFailures,jdbcType=TINYINT}
  AND execute_status = 10

mapper.select:
SELECT EXISTS (
  SELECT 1
  FROM sched_task
  WHERE task_id = #{taskId,jdbcType=BIGINT}
    AND execute_status = 20
    AND worker = #{worker,jdbcType=VARCHAR}
    AND idempotency_key = #{idempotencyKey,jdbcType=VARCHAR}
) e

mapper.update:
UPDATE sched_task
SET 
      execute_end_time = IF(execute_start_time IS NULL, NULL, #{executeEndTime,jdbcType=TIMESTAMP}),


      error_msg = #{errorMsg,jdbcType=VARCHAR},

    execute_status = #{toStatus,jdbcType=TINYINT}
WHERE task_id = #{taskId,jdbcType=BIGINT}

    AND worker = #{worker,jdbcType=VARCHAR}

  AND execute_status = #{fromStatus,jdbcType=TINYINT}
  AND execute_status != #{toStatus,jdbcType=TINYINT}
  AND execute_status IN (10, 20, 30)

UPDATE sched_task
SET 
      execute_end_time = IF(execute_start_time IS NULL, NULL, #{executeEndTime,jdbcType=TIMESTAMP}),

    execute_status = #{toStatus,jdbcType=TINYINT}
WHERE instance_id = #{instanceId,jdbcType=BIGINT}
  AND execute_status != #{toStatus,jdbcType=TINYINT}
  AND execute_status IN (#{status,jdbcType=TINYINT})

UPDATE sched_task
SET execute_status = #{toStatus,jdbcType=TINYINT}
WHERE instance_id = #{instanceId,jdbcType=BIGINT}
  AND execute_status != #{toStatus,jdbcType=TINYINT}
  AND execute_status != 20
  AND #{toStatus,jdbcType=TINYINT} != 20

UPDATE sched_task
SET execution_data = #{executionData,jdbcType=LONGVARCHAR}
WHERE task_id = #{taskId,jdbcType=BIGINT}
  AND execute_status = 20
  AND worker = #{worker,jdbcType=VARCHAR}

