DELETE FROM sched_task
WHERE instance_id = #{instanceId,jdbcType=BIGINT}
  AND (SELECT cnt FROM (SELECT COUNT(*) cnt FROM sched_task WHERE instance_id = #{instanceId,jdbcType=BIGINT} AND execute_status < 40) t)=0
